fun solve(n: Long): Boolean {
    var sum = 0L
    var product = 1L
    var num = n
    var hasZero = false

    while (num > 0) {
        val digit = num % 10
        sum += digit
        product *= digit
        num /= 10
        if (digit == 0L) {
            hasZero = true
        }
    }

    if (hasZero) {
        product = 0
    }

    val total = sum + product
    return if (total == 0L) false else n % total == 0L
}
